PythonGo <pre><code>class Report:
    def __init__(self, rows: list[dict]) -&gt; None:
        self.rows = rows

    def calculate_totals(self) -&gt; float:
        return sum(r["amount"] for r in self.rows)

    def render_html(self) -&gt; str:
        html = "&lt;table&gt;"
        for r in self.rows:
            html += f"&lt;tr&gt;&lt;td&gt;{r['name']}&lt;/td&gt;&lt;td&gt;{r['amount']}&lt;/td&gt;&lt;/tr&gt;"
        html += "&lt;/table&gt;"
        return html

    def save_to_disk(self, path: str) -&gt; None:
        with open(path, "w") as f:
            f.write(self.render_html())
</code></pre> <pre><code>type Report struct {
    Rows []Row
}

func (r *Report) CalculateTotals() float64 {
    var total float64
    for _, row := range r.Rows {
        total += row.Amount
    }
    return total
}

func (r *Report) RenderHTML() string {
    var b strings.Builder
    b.WriteString("&lt;table&gt;")
    for _, row := range r.Rows {
        fmt.Fprintf(&amp;b, "&lt;tr&gt;&lt;td&gt;%s&lt;/td&gt;&lt;td&gt;%.2f&lt;/td&gt;&lt;/tr&gt;", row.Name, row.Amount)
    }
    b.WriteString("&lt;/table&gt;")
    return b.String()
}

func (r *Report) SaveToDisk(path string) error {
    return os.WriteFile(path, []byte(r.RenderHTML()), 0o644)
}
</code></pre> <p>Класс совмещает бизнес-логику (<code>calculate_totals</code>), представление (<code>render_html</code>) и инфраструктуру (<code>save_to_disk</code>). Любое из трёх требований («считать с НДС», «вместо HTML — PDF», «класть в S3 вместо диска») заставит лезть в один и тот же файл, плодить флаги и условные ветки.</p>

PythonGo <pre><code>from typing import Protocol


class Calculator:
    def totals(self, rows: list[dict]) -&gt; float:
        return sum(r["amount"] for r in rows)


class HtmlRenderer:
    def render(self, rows: list[dict]) -&gt; str:
        html = "&lt;table&gt;"
        for r in rows:
            html += f"&lt;tr&gt;&lt;td&gt;{r['name']}&lt;/td&gt;&lt;td&gt;{r['amount']}&lt;/td&gt;&lt;/tr&gt;"
        return html + "&lt;/table&gt;"


class Storage(Protocol):
    def save(self, name: str, content: str) -&gt; None: ...


class FileStorage:
    def save(self, name: str, content: str) -&gt; None:
        with open(name, "w") as f:
            f.write(content)
</code></pre> <pre><code>type Calculator struct{}

func (Calculator) Totals(rows []Row) float64 { /* ... */ }

type HtmlRenderer struct{}

func (HtmlRenderer) Render(rows []Row) string { /* ... */ }

type Storage interface {
    Save(name string, content []byte) error
}

type FileStorage struct{}

func (FileStorage) Save(name string, content []byte) error {
    return os.WriteFile(name, content, 0o644)
}
</code></pre> <p>Каждый класс отвечает за одну роль. Поменять формат отчёта — поправить <code>HtmlRenderer</code>. Положить файл в S3 — добавить <code>S3Storage</code>, реализующий тот же интерфейс. Логика подсчёта остаётся в покое.</p> <p>Не путайте SRP с «один метод на класс». Класс может иметь десяток методов — лишь бы все они служили одной ответственности. Класс <code>User</code> с методами <code>set_email</code>, <code>validate_email</code>, <code>change_password</code> — это нормальная ответственность «модель пользователя».</p>

PythonGo <pre><code>class PaymentProcessor:
    def pay(self, method: str, amount: float) -&gt; None:
        if method == "card":
            # ... обращение к платёжному шлюзу
            pass
        elif method == "sbp":
            # ... СБП
            pass
        elif method == "wallet":
            # ... криптокошелёк
            pass
        else:
            raise ValueError(f"unknown method: {method}")
</code></pre> <pre><code>type PaymentProcessor struct{}

func (p *PaymentProcessor) Pay(method string, amount float64) error {
    switch method {
    case "card":
        // ...
    case "sbp":
        // ...
    case "wallet":
        // ...
    default:
        return fmt.Errorf("unknown method: %s", method)
    }
    return nil
}
</code></pre> <p>Добавление нового способа оплаты — это новая ветка <code>elif</code>/<code>case</code>. Класс закрыт от расширения: каждый раз меняется существующий код, растёт риск задеть работающие методы.</p>

PythonGo <pre><code>from typing import Protocol


class PaymentMethod(Protocol):
    def pay(self, amount: float) -&gt; None: ...


class CardPayment:
    def pay(self, amount: float) -&gt; None:
        # ... шлюз ...
        pass


class SbpPayment:
    def pay(self, amount: float) -&gt; None:
        # ... СБП ...
        pass


class PaymentProcessor:
    def __init__(self, method: PaymentMethod) -&gt; None:
        self.method = method

    def charge(self, amount: float) -&gt; None:
        self.method.pay(amount)
</code></pre> <pre><code>type PaymentMethod interface {
    Pay(amount float64) error
}

type CardPayment struct{}
func (CardPayment) Pay(amount float64) error { /* ... */ return nil }

type SbpPayment struct{}
func (SbpPayment) Pay(amount float64) error { /* ... */ return nil }

type PaymentProcessor struct {
    Method PaymentMethod
}

func (p *PaymentProcessor) Charge(amount float64) error {
    return p.Method.Pay(amount)
}
</code></pre> <p>Новый способ оплаты — новый тип, реализующий интерфейс. <code>PaymentProcessor</code> остаётся закрыт от изменения и открыт для расширения.</p> <p>OCP не означает «никогда не править существующий код». Если требования изменились существенно — рефакторите. OCP про другое: типовые добавления (новый платёжный метод, новый формат отчёта) должны быть аддитивными.</p>

PythonGo <pre><code>class Rectangle:
    def __init__(self, width: int, height: int) -&gt; None:
        self.width = width
        self.height = height

    def set_width(self, w: int) -&gt; None:
        self.width = w

    def set_height(self, h: int) -&gt; None:
        self.height = h

    def area(self) -&gt; int:
        return self.width * self.height


class Square(Rectangle):
    def set_width(self, w: int) -&gt; None:
        self.width = w
        self.height = w  # ломаем контракт: меняем больше, чем просили

    def set_height(self, h: int) -&gt; None:
        self.width = h
        self.height = h


def grow(r: Rectangle) -&gt; None:
    r.set_width(10)
    r.set_height(20)
    assert r.area() == 200  # на Square — провал: area == 400
</code></pre> <p>Go не имеет наследования — этот антипример просто не возникает на уровне типов. Аналог через встраивание:</p> <pre><code>type Rectangle struct {
    Width, Height int
}

func (r *Rectangle) SetWidth(w int)  { r.Width = w }
func (r *Rectangle) SetHeight(h int) { r.Height = h }
func (r *Rectangle) Area() int       { return r.Width * r.Height }

type Square struct {
    Rectangle // встраивание не значит «is-a»: это просто переиспользование полей
}

// Если переопределим SetWidth — получим ту же проблему, что в Python.
func (s *Square) SetWidth(w int) {
    s.Width = w
    s.Height = w
}
</code></pre> <p>Geometrically <code>Square is-a Rectangle</code> — кажется логичным. Но поведенчески прямоугольник позволяет независимо менять ширину и высоту, а квадрат нет. Лисков ломается. Решение — композиция вместо наследования или другой иерархический корень (<code>Shape</code> + <code>area()</code>).</p>

